  function handleDeleteConfirmed() {
    setShowDeleteConfirm(false);
    onDelete?.();
  }

  return (
    <div style={{ fontFamily: "system-ui, sans-serif", padding: "16px" }}>
      {/* Phase Number — read-only display */}
      <div style={FIELD_STYLE}>
