            color: "#fff",
            border: "none",
            borderRadius: "6px",
            cursor: dirty ? "pointer" : "default",
            fontSize: "13px",
            fontWeight: 500,
          }}
        >
          Save
        </button>
        <button
          onClick={onCancel}
          style={{
            padding: "7px 18px",
            backgroundColor: "#f3f4f6",
            color: "#374151",
            border: "1px solid #d1d5db",
            borderRadius: "6px",
            cursor: "pointer",
            fontSize: "13px",
            fontWeight: 500,
          }}
        >
          Cancel
        </button>
        {onDelete && !showDeleteConfirm && (
          <button
            onClick={() => setShowDeleteConfirm(true)}
            style={{
              marginLeft: "auto",
              padding: "7px 14px",
              backgroundColor: "#fff",
              color: "#dc2626",
              border: "1px solid #fca5a5",
              borderRadius: "6px",
              cursor: "pointer",
              fontSize: "13px",
              fontWeight: 500,
            }}
          >
            Delete Phase
